// ── Features Carousel ──
function FeaturesCarousel({ features }) {
  const [current, setCurrent] = useState(0)
  const [isPaused, setIsPaused] = useState(false)
  const trackRef = useRef(null)

  useEffect(() => {
    if (features.length <= 1 || isPaused) return
    const t = setInterval(() => setCurrent(c => (c + 1) % features.length), 3000)
    return () => clearInterval(t)
  }, [features.length, isPaused])

  useEffect(() => {
    if (!trackRef.current || features.length === 0) return
    const track = trackRef.current
    const card = track.children[current]
    if (!card) return
    const trackLeft = track.getBoundingClientRect().left
    const cardLeft = card.getBoundingClientRect().left
    track.scrollBy({ left: cardLeft - trackLeft, behavior: 'smooth' })
  }, [current, features.length])

  if (features.length === 0) return null

  return (
    <>
      <div className="features-carousel-wrap"
        onMouseEnter={() => setIsPaused(true)}
        onMouseLeave={() => setIsPaused(false)}>

        <div className="features-fade features-fade-left" />

        <div className="features-track" ref={trackRef}>
          {features.map((f, i) => (
            <div key={i} className={`feature-card${i === current ? ' active' : ''}`}
              onClick={() => setCurrent(i)}>
              <span className="feature-icon">{f.icon}</span>
              <h3 className="feature-title">{f.title}</h3>
              <p className="feature-desc">{f.desc}</p>
            </div>
          ))}
        </div>

        <div className="features-fade features-fade-right" />

        {features.length > 1 && (
          <>
            <button className="features-arrow features-arrow-prev"
              onClick={() => { setCurrent(c => (c - 1 + features.length) % features.length); setIsPaused(true); setTimeout(() => setIsPaused(false), 6000) }}>
              &#8592;
            </button>
            <button className="features-arrow features-arrow-next"
              onClick={() => { setCurrent(c => (c + 1) % features.length); setIsPaused(true); setTimeout(() => setIsPaused(false), 6000) }}>
              &#8594;
            </button>
          </>
        )}
      </div>

      {features.length > 1 && (
        <div className="features-dots">
          {features.map((_, i) => (
            <button key={i} className={`features-dot${i === current ? ' active' : ''}`}
              onClick={() => { setCurrent(i); setIsPaused(true); setTimeout(() => setIsPaused(false), 6000) }} />
          ))}
        </div>
      )}

      {features.length > 1 && !isPaused && (
        <div className="features-progress-bar" key={current}>
          <div className="features-progress-fill" />
        </div>
      )}
    </>
  )
}

// ── Reviews Display Component ──
function ReviewsDisplay({ refreshKey }) {
  const [reviews, setReviews] = useState([])
  const [loading, setLoading] = useState(true)
  const [current, setCurrent] = useState(0)
  const [isPaused, setIsPaused] = useState(false)
  const trackRef = useRef(null)
  const timerRef = useRef(null)

  useEffect(() => {
    setLoading(true)
    fetch(`${API_BASE}/api/reviews`)
      .then(r => r.json())
      .then(d => { setReviews(d.data || []); setLoading(false) })
      .catch(() => setLoading(false))
  }, [refreshKey])

  // Auto-scroll every 3 seconds
  useEffect(() => {
    if (reviews.length <= 1 || isPaused) return
    timerRef.current = setInterval(() => {
      setCurrent(c => (c + 1) % reviews.length)
    }, 3000)
    return () => clearInterval(timerRef.current)
  }, [reviews.length, isPaused])

  // Scroll ONLY the track (not the page) when current changes
  useEffect(() => {
    if (!trackRef.current || reviews.length === 0) return
    const track = trackRef.current
    const card = track.children[current]
    if (!card) return
    const trackLeft = track.getBoundingClientRect().left
    const cardLeft = card.getBoundingClientRect().left
    track.scrollBy({ left: cardLeft - trackLeft, behavior: 'smooth' })
  }, [current, reviews.length])

  const Stars = ({ rating }) => (
    <div className="review-stars">
      {[1,2,3,4,5].map(n => (
        <span key={n} className={`review-star${n > rating ? ' empty' : ''}`}>★</span>
      ))}
    </div>
  )

  const avgRating = reviews.length
    ? (reviews.reduce((s, r) => s + r.rating, 0) / reviews.length).toFixed(1)
    : null

  if (loading) return (
    <div className="reviews-loading">
      <div className="reviews-loading-dots"><span /><span /><span /></div>
    </div>
  )

  if (reviews.length === 0) return (
    <div className="reviews-empty">
      <div className="reviews-empty-icon">⭐</div>
      <div className="reviews-empty-text">Be The First To Leave A Review</div>
    </div>
  )

  return (
    <>
      <div className="reviews-summary">
        <div className="reviews-avg-score">{avgRating}</div>
        <div className="reviews-avg-right">
          <div className="reviews-avg-stars">
            {[1,2,3,4,5].map(n => (
              <span key={n} className={`review-star${n > Math.round(avgRating) ? ' empty' : ''}`}>★</span>
            ))}
          </div>
          <div className="reviews-avg-label">
            Average Rating &middot; {reviews.length} {reviews.length === 1 ? 'Review' : 'Reviews'}
          </div>
        </div>
      </div>

      {/* Carousel wrapper */}
      <div className="reviews-carousel-wrap"
        onMouseEnter={() => setIsPaused(true)}
        onMouseLeave={() => setIsPaused(false)}>

        {/* Left fade */}
        <div className="reviews-fade reviews-fade-left" />

        {/* Scrollable track */}
        <div className="reviews-track" ref={trackRef}>
          {reviews.map((r, i) => (
            <div
              key={i}
              className={`review-card${i === current ? ' active' : ''}`}
              onClick={() => setCurrent(i)}
            >
              <Stars rating={r.rating} />
              <p className="review-message">"{r.message}"</p>
              <span className="review-author">— {r.name}</span>
            </div>
          ))}
        </div>

        {/* Right fade */}
        <div className="reviews-fade reviews-fade-right" />

        {/* Prev / Next arrows */}
        {reviews.length > 1 && (
          <>
            <button className="reviews-arrow reviews-arrow-prev"
              onClick={() => { setCurrent(c => (c - 1 + reviews.length) % reviews.length); setIsPaused(true); setTimeout(() => setIsPaused(false), 6000) }}>
              &#8592;
            </button>
            <button className="reviews-arrow reviews-arrow-next"
              onClick={() => { setCurrent(c => (c + 1) % reviews.length); setIsPaused(true); setTimeout(() => setIsPaused(false), 6000) }}>
              &#8594;
            </button>
          </>
        )}
      </div>

      {/* Dot indicators */}
      {reviews.length > 1 && (
        <div className="reviews-dots">
          {reviews.map((_, i) => (
            <button key={i} className={`reviews-dot${i === current ? ' active' : ''}`}
              onClick={() => { setCurrent(i); setIsPaused(true); setTimeout(() => setIsPaused(false), 6000) }} />
          ))}
        </div>
      )}

      {/* Progress bar showing 3s until next */}
      {reviews.length > 1 && !isPaused && (
        <div className="reviews-progress-bar" key={current}>
          <div className="reviews-progress-fill" />
        </div>
      )}
    </>
  )
}

// ── Review Submission Form ──
function ReviewForm({ onSubmitted }) {
  const [name, setName] = useState('')
  const [rating, setRating] = useState(0)
  const [hoverRating, setHoverRating] = useState(0)
  const [message, setMessage] = useState('')
  const [status, setStatus] = useState(null)
  const [submitting, setSubmitting] = useState(false)

  const handleSubmit = async () => {
    if (!name.trim() || !rating || !message.trim()) { setStatus('error'); return }
    setSubmitting(true)
    try {
      const res = await fetch(`${API_BASE}/api/reviews`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name, rating, message })
      })
      if (res.ok) {
        setStatus('success'); setName(''); setRating(0); setMessage('')
        // Re-fetch reviews without page reload
        if (onSubmitted) onSubmitted()
      }
      else setStatus('error')
    } catch { setStatus('error') }
    finally { setSubmitting(false) }
  }

  return (
    <div className="review-form-wrap">
      <h3 className="review-form-title">Leave a Review</h3>
      <p className="review-form-sub">Share your Kirola Fitness experience</p>
      <div className="review-form-row">
        <div className="review-form-field">
          <label>Your Name</label>
          <input type="text" placeholder="John Doe" value={name} onChange={e => setName(e.target.value)} />
        </div>
        <div className="review-form-field">
          <label>Rating</label>
          <div className="review-star-input">
            {[1,2,3,4,5].map(n => (
              <button key={n} className={`review-star-btn${n <= (hoverRating || rating) ? ' active' : ''}`}
                onMouseEnter={() => setHoverRating(n)} onMouseLeave={() => setHoverRating(0)}
                onClick={() => setRating(n)}>★</button>
            ))}
          </div>
        </div>
      </div>
      <div className="review-form-field">
        <label>Your Review</label>
        <textarea rows={4} placeholder="Tell us about your experience..." value={message} onChange={e => setMessage(e.target.value)} />
      </div>
      <button className="btn-primary" onClick={handleSubmit} disabled={submitting}>
        {submitting ? 'Submitting...' : 'Submit Review'}
      </button>
      {status === 'success' && <p className="review-submit-msg success">✓ Review submitted! It will appear after approval.</p>}
      {status === 'error' && <p className="review-submit-msg error">✗ Please fill in all fields and select a rating.</p>}
    </div>
  )
}

