// ── Manager Password Gate ──
const MANAGER_PASSWORD = 'WEALLCANDOITKIROLA'

function ManagerGate() {
  const [unlocked, setUnlocked] = useState(() => sessionStorage.getItem('mgr_auth') === '1')
  const [input, setInput] = useState('')
  const [shake, setShake] = useState(false)
  const [showPw, setShowPw] = useState(false)
  const inputRef = useRef(null)

  useEffect(() => { if (!unlocked) setTimeout(() => inputRef.current?.focus(), 100) }, [unlocked])

  const attempt = () => {
    if (input === MANAGER_PASSWORD) {
      sessionStorage.setItem('mgr_auth', '1')
      setUnlocked(true)
    } else {
      setShake(true)
      setInput('')
      setTimeout(() => setShake(false), 600)
      setTimeout(() => inputRef.current?.focus(), 50)
    }
  }

  if (unlocked) return <Manager />

  return (
    <div style={{
      minHeight: '100vh', background: '#060810',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      fontFamily: "'Barlow', sans-serif", padding: 20
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Barlow:wght@400;600&family=Barlow+Condensed:wght@400;600;700&display=swap');
        @keyframes mgr-shake {
          0%,100% { transform: translateX(0); }
          20%,60% { transform: translateX(-8px); }
          40%,80% { transform: translateX(8px); }
        }
        @keyframes mgr-fadein { from { opacity:0; transform:translateY(16px); } to { opacity:1; transform:translateY(0); } }
        .mgr-gate-box { animation: mgr-fadein 0.4s ease; }
        .mgr-gate-shake { animation: mgr-shake 0.5s ease !important; }
        .mgr-pw-input:focus { border-color: rgba(201,168,76,0.6) !important; outline: none; }
        .mgr-pw-input::placeholder { color: rgba(255,255,255,0.15); }
        .mgr-unlock-btn:hover { background: #b8963e !important; }
      `}</style>

      <div className="mgr-gate-box" style={{ width: '100%', maxWidth: 400, textAlign: 'center' }}>

        {/* Lock icon */}
        <div style={{
          width: 72, height: 72, borderRadius: '50%',
          background: 'rgba(201,168,76,0.08)', border: '1px solid rgba(201,168,76,0.2)',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontSize: 28, margin: '0 auto 28px'
        }}>🔐</div>

        <p style={{ fontFamily: "'Barlow Condensed',sans-serif", fontSize: 11, letterSpacing: 5, fontWeight: 700, textTransform: 'uppercase', color: '#c9a84c', marginBottom: 10 }}>
          Restricted Access
        </p>
        <h1 style={{ fontFamily: "'Bebas Neue',cursive", fontSize: 42, letterSpacing: 2, color: '#fff', marginBottom: 8, lineHeight: 1 }}>
          Content Manager
        </h1>
        <p style={{ fontFamily: "'Barlow Condensed',sans-serif", fontSize: 13, color: 'rgba(255,255,255,0.3)', letterSpacing: 1, marginBottom: 40 }}>
          Enter the password to continue
        </p>

        {/* Input row */}
        <div className={shake ? 'mgr-gate-shake' : ''} style={{ position: 'relative', marginBottom: 16 }}>
          <input
            ref={inputRef}
            className="mgr-pw-input"
            type={showPw ? 'text' : 'password'}
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && attempt()}
            placeholder="Enter password"
            style={{
              width: '100%', padding: '16px 52px 16px 20px',
              background: 'rgba(255,255,255,0.04)',
              border: '1px solid rgba(255,255,255,0.1)',
              color: '#fff', fontSize: 16, letterSpacing: 3,
              fontFamily: "'Barlow Condensed',sans-serif",
              borderRadius: 0, transition: 'border-color 0.2s'
            }}
          />
          {/* Show/hide toggle */}
          <button
            onClick={() => setShowPw(v => !v)}
            style={{
              position: 'absolute', right: 14, top: '50%', transform: 'translateY(-50%)',
              background: 'none', border: 'none', cursor: 'pointer',
              fontSize: 18, opacity: 0.4, color: '#fff', padding: 4,
              transition: 'opacity 0.2s'
            }}
            onMouseEnter={e => e.currentTarget.style.opacity = '0.8'}
            onMouseLeave={e => e.currentTarget.style.opacity = '0.4'}
          >
            {showPw ? '🙈' : '👁'}
          </button>
        </div>

        <button
          className="mgr-unlock-btn"
          onClick={attempt}
          style={{
            width: '100%', padding: '16px',
            background: '#c9a84c', border: 'none', color: '#060810',
            fontFamily: "'Barlow Condensed',sans-serif", fontSize: 13,
            letterSpacing: 4, fontWeight: 700, textTransform: 'uppercase',
            cursor: 'pointer', transition: 'background 0.2s'
          }}
        >
          Unlock Manager →
        </button>

        <p style={{ marginTop: 24, fontFamily: "'Barlow Condensed',sans-serif", fontSize: 11, letterSpacing: 2, color: 'rgba(255,255,255,0.1)', textTransform: 'uppercase' }}>
          Kirola Fitness · Admin Only
        </p>
      </div>
    </div>
  )
}

